ALTER TABLE public.business_settings
  ADD COLUMN IF NOT EXISTS data_retention_statement text DEFAULT 'In accordance with NHS and UK healthcare record-keeping guidelines, adult patient records are automatically deleted 8 years after their last appointment (or 8 years after death). Records for patients who were under 18 at the time of treatment are retained until their 25th birthday (or 26th if they were 17 at the conclusion of treatment). This process runs automatically to ensure GDPR compliance.',
  ADD COLUMN IF NOT EXISTS ai_usage_statement text DEFAULT 'ShawScope does NOT use AI features on any identifiable patient data. All previous AI-assisted clinical tools (diagnostic photo analysis, dictation, summarisation, letter writing, chat) have been removed from this system to guarantee patient confidentiality. Any remaining AI features (e.g. social media drafting or expense receipt OCR) operate only on non-patient business content.',
  ADD COLUMN IF NOT EXISTS data_storage_statement text DEFAULT 'All patient data (records, appointments, consent forms, clinical notes and uploaded files) is stored within a UK/EU-hosted, encrypted database protected by Row-Level Security and admin-only access policies. Files are served through short-lived signed URLs and never exposed publicly. Access to this admin portal is protected by 2FA (SMS OTP) and biometric device login. Backups are encrypted and retained in line with the retention policy above.';
